import json, sys
baseline = json.load(open('baseline-packages.json'))
after = json.load(sys.stdin)

def get_pkgs(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(name, {})[pkg['id']] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
if b == a:
    print('✅ All packages resolve to identical versions as baseline.')
else:
    print('❌ Differences detected:')
    for proj in sorted(set(list(b.keys()) + list(a.keys()))):
        for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
            bv = b.get(proj,{}).get(pkg)
            av = a.get(proj,{}).get(pkg)
            if bv != av:
                print(f'  {proj} / {pkg}: {bv} -> {av}')
"

